import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface RolloutData {
  featureName: string;
  rollout: {
    percentage: number;
    activeUsers: number;
    errorRate: number;
  };
  adoptionTrend: {
    week: string;
    percentage: number;
  }[];
  errorTrend: number[];
}

export default function Widget() {
  const data = response.data as RolloutData;
  const { featureName, rollout, adoptionTrend, errorTrend } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: response.meta.primaryColor, mb: 1 }}>
              {featureName} Rollout
            </Typography>
            <Stack direction="row" alignItems="center" spacing={1}>
              <Chip
                icon={rollout.percentage >= 50 ? <TrendingUp /> : <TrendingDown />}
                label={`${rollout.percentage}%`}
                sx={{ bgcolor: response.meta.accentColor, color: '#FFFFFF' }}
              />
              <Typography variant="body2" color="text.secondary">
                Active Users: {rollout.activeUsers.toLocaleString()}
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: adoptionTrend.map((trend) => trend.percentage),
                  color: response.meta.primaryColor,
                  label: 'Adoption Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: adoptionTrend.map((trend) => trend.week),
                  id: 'weeks',
                },
              ]}
              yAxis={[{ id: 'percentage' }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="weeks"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="percentage"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="caption" color="text.secondary">
              Error Rate: {rollout.errorRate}%
            </Typography>
            <LinePlot
              height={50}
              series={[{ data: errorTrend, color: '#FF5722', curve: 'linear', showMark: false }]}
              xAxis={[{ data: errorTrend.map((_, i) => i), hide: true }]}
              margin={{ top: 5, bottom: 5, left: 0, right: 0 }}
              sx={{ '& .MuiLineElement-root': { strokeWidth: 1.5 } }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
